    @Test
    fun testCancelFutureTriggeringGlobalHandler() = runTest {
        val future = GlobalScope.future(Dispatchers.Default) {
            try {
                delay(1000)
            } finally {
                throw Exception("foo")
            }
        }
        yield() // let the coroutine start
